import React, { createContext, useState, useContext, useEffect } from 'react';
import api from '../api/axios';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const checkAuth = async () => {
            const token = localStorage.getItem('accessToken');
            if (token) {
                try {
                    // Эндпоинт /api/auth/me должен быть в app.js
                    const response = await api.get('/api/auth/me');
                    setUser(response.data);
                } catch (error) {
                    localStorage.removeItem('accessToken');
                    localStorage.removeItem('refreshToken');
                }
            }
            setLoading(false);
        };
        checkAuth();
    }, []);

    const login = async (username, password) => {
    try {
        const response = await api.post('/api/auth/login', { username, password });
        console.log('Ответ сервера:', response.data);

        // Добавляем username в список извлекаемых полей
        const { accessToken, refreshToken, id, role, username: serverUsername } = response.data;

        localStorage.setItem('accessToken', accessToken);
        localStorage.setItem('refreshToken', refreshToken);

        // Убеждаемся, что данные записаны корректно
        const userData = { id, username: serverUsername, role };
        setUser(userData);

        return response.data;
    } catch (error) {
        console.error('Ошибка входа в контексте:', error.response?.data || error.message);
        throw error; // Пробрасываем ошибку дальше в компонент Login
    }
};

    const register = async (username, password, role = 'user') => {
        try {
            const response = await api.post('/api/auth/register', { username, password, role });
            const { accessToken, refreshToken, id, role: userRole } = response.data;

            localStorage.setItem('accessToken', accessToken);
            localStorage.setItem('refreshToken', refreshToken);

            const userData = { id, username: response.data.username, role: userRole };
            setUser(userData);
            return response.data;
        } catch (error) {
            console.error('Ошибка регистрации:', error.response?.data || error.message);
            throw error;
        }
    };

    const logout = () => {
        localStorage.removeItem('accessToken');
        localStorage.removeItem('refreshToken');
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ 
            user, login, register, logout, loading,
            isAdmin: user?.role === 'admin'
        }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);
